#graphql
query PriceListUpdateCurrencyFixedPricesProductDiscovery($first: Int!) {
  products(first: $first) {
    nodes {
      id
      title
      variants(first: 5) {
        nodes {
          id
          title
          sku
        }
      }
    }
  }
}

cases.query:
#graphql
query CatalogRelationMarketsRead($first: Int!) {
  markets(first: $first) {
    nodes {
      id
      name
      handle
      status
      enabled
    }
  }
}

#graphql
query PriceListUpdateCurrencyFixedPricesHydrate($variantIds: [ID!]!) {
  nodes(ids: $variantIds) {
    __typename
    ... on ProductVariant {
      id
      title
      sku
      price
      compareAtPrice
      product {
        id
        title
        handle
        status
        variants(first: 10) {
          nodes {
            id
            title
            sku
            price
            compareAtPrice
          }
        }
      }
    }
  }
}

#graphql
mutation PriceListCreateCatalogValidation($input: PriceListCreateInput!) {
  priceListCreate(input: $input) {
    priceList {
      id
      currency
      parent {
        adjustment {
          type
          value
        }
      }
    }
    userErrors {
      field
      message
      code
    }
  }
}

#graphql
mutation CatalogCreateRelationValidation($input: CatalogCreateInput!) {
  catalogCreate(input: $input) {
    catalog {
      id
    }
    userErrors {
      field
      message
      code
    }
  }
}

mutation PriceListFixedPricesAdd($priceListId: ID!, $prices: [PriceListPriceInput!]!) {
  priceListFixedPricesAdd(priceListId: $priceListId, prices: $prices) {
    prices {
      price {
        amount
        currencyCode
      }
      compareAtPrice {
        amount
        currencyCode
      }
      originType
      variant {
        id
        sku
        product {
          id
          title
        }
      }
    }
    userErrors {
      field
      message
      code
    }
  }
}

#graphql
query PriceListUpdateCurrencyFixedPricesRead($priceListId: ID!, $catalogId: ID!) {
  priceList(id: $priceListId) {
    id
    name
    currency
    fixedPricesCount
    parent {
      adjustment {
        type
        value
      }
    }
    catalog {
      id
      title
      status
    }
    prices(first: 10, originType: FIXED) {
      edges {
        cursor
        node {
          price {
            amount
            currencyCode
          }
          compareAtPrice {
            amount
            currencyCode
          }
          originType
          variant {
            id
            sku
            product {
              id
              title
            }
          }
        }
      }
      pageInfo {
        hasNextPage
        hasPreviousPage
        startCursor
        endCursor
      }
    }
  }
  catalog(id: $catalogId) {
    id
    title
    status
    ... on MarketCatalog {
      priceList {
        id
        currency
        fixedPricesCount
      }
    }
  }
}

